y-100 text-gray-600' } ?>"><?= match($b['status']) { 'draft' => 'Rascunho', 'sent' => 'Enviado', 'viewed' => 'Visualizado', 'approved' => 'Aprovado', 'rejected' => 'Recusado', 'expired' => 'Expirado', default => $b['status'] } ?></span></td><td class="px-4 py-3 text-sm text-gray-500"><?= date('d/m/Y', strtotime($b['created_at'])) ?></td><td class="px-4 py-3 text-right"><div class="flex items-center justify-end gap-1"><a href="/admin/orcamentos/<?= $b['id'] ?>" class="p-1.5 rounded-lg text-gray-400 hover:text-purple-600 hover:bg-purple-50 dark:hover:bg-purple-900/20 transition" title="Ver"><i data-lucide="eye" class="w-4 h-4"></i></a><a href="/admin/orcamentos/<?= $b['id'] ?>/editar" class="p-1.5 rounded-lg text-gray-400 hover:text-blue-600 hover:bg-blue-50 dark:hover:bg-blue-900/20 transition" title="Editar"><i data-lucide="pencil" class="w-4 h-4"></i></a><button onclick="confirmDelete('/admin/orcamentos/<?= $b['id'] ?>')" class="p-1.5 rounded-lg text-gray-400 hover:text-red-600 hover:bg-red-50 dark:hover:bg-red-900/20 transition" title="Excluir"><i data-lucide="trash-2" class="w-4 h-4"></i></button></div></td></tr><?php endforeach; ?><?php if (empty($budgets)): ?><tr><td colspan="6" class="px-4 py-12 text-center text-gray-500">Nenhum orçamento.</td></tr><?php endif; ?></tbody></table></div></div>